={
  "model": "minimax-m2:cloud",
  "prompt": "你是台灣消費者保護法專家。請分析以下合約文本，找出所有違反台灣消費者保護法的條款。

請以JSON格式回傳，格式如下：
{"violations": [{"id": 1, "clause": "條款名稱", "riskLevel": "高/中/低", "reason": "違法原因", "details": "詳細說明"}], "riskScore": 1-10, "totalViolations": N, "summary": "總結"}

合約文本：
{{ $json.body.text || $json.text }}",
  "stream": false
}

parameters.jsCode:
// ============================================================
// n8n Code Node — 合約分析結果解析器
// 將 Ollama (minimax-m2:cloud) 的回應轉換為結構化 JSON
// ============================================================

// 1. 取得上游 HTTP Request 節點的資料
const ollamaRaw = $node["HTTP Request"].json;
const inputText = $node["Webhook"].json.body?.text || $node["Webhook"].json.text || "";

// 2. 提取 Ollama 回應文字
let responseText = "";
if (ollamaRaw && ollamaRaw.response) {
  responseText = ollamaRaw.response;
} else if (ollamaRaw && ollamaRaw.message && ollamaRaw.message.content) {
  responseText = ollamaRaw.message.content;
} else if (typeof ollamaRaw === "string") {
  responseText = ollamaRaw;
}

// 3. 嘗試從回應中解析 JSON
let parsedResult = null;
try {
  parsedResult = JSON.parse(responseText);
} catch (e) {
  const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try { parsedResult = JSON.parse(jsonMatch[1].trim()); } catch (e2) {}
  }
}

// 4. 若解析成功直接使用
if (parsedResult && Array.isArray(parsedResult.violations)) {
  const violations = parsedResult.violations.map((v, i) => ({
    id: v.id || i + 1,
    clause: v.clause || v.條款 || v.name || "未知條款",
    riskLevel: v.riskLevel || v.risk_level || v.風險等級 || "中",
    reason: v.reason || v.原因 || "違反消保法",
    details: v.details || v.詳細 || v.description || "",
  }));
  const riskScore = Math.min(10, Math.max(1, Math.round(parsedResult.riskScore || calculateScore(violations))));
  return [{ json: { violations, riskScore, totalViolations: violations.length, summary: parsedResult.summary || generateSummary(violations, riskScore) } }];
}

// 5. 備援：關鍵詞匹配
const violationPatterns = [
  { keywords: ["概不退費","不得退款","不退款","不予退還","無法退費"], clause: "不合理退費條款", riskLevel: "高", reason: "違反消保法第 19 條", details: "消費者享有法定退費權利" },
  { keywords: ["自動扣費","自動續約","自動扣款","自動繳費"], clause: "自動扣費／自動續約條款", riskLevel: "高", reason: "違反消保法第 17 條", details: "自動扣費需事先取得消費者明確同意" },
  { keywords: ["概不負責","不負任何責任","免除一切責任","不承擔責任"], clause: "全面免責條款", riskLevel: "高", reason: "違反消保法第 7 條", details: "不得以契約完全免除責任" },
  { keywords: ["責任限制","賠償上限","最高賠償","賠償不超過"], clause: "責任限制條款", riskLevel: "中", reason: "違反消保法第 7 條", details: "賠償上限需合理" },
  { keywords: ["單方修改","隨時修改","有權修改","得修改條款"], clause: "單方修改條款", riskLevel: "高", reason: "違反消保法第 12 條", details: "不得單方修改契約" },
  { keywords: ["強制仲裁","不得提起訴訟","放棄訴訟"], clause: "強制仲裁條款", riskLevel: "高", reason: "違反消保法第 10 條", details: "消費者不得被強制放棄訴訟權" },
];

const violations = [];
for (const p of violationPatterns) {
  if (p.keywords.some(kw => inputText.includes(kw) || responseText.includes(kw))) {
    violations.push({ id: violations.length + 1, clause: p.clause, riskLevel: p.riskLevel, reason: p.reason, details: p.details });
  }
}

const riskScore = calculateScore(violations);
return [{ json: { violations, riskScore, totalViolations: violations.length, summary: generateSummary(violations, riskScore) } }];

function calculateScore(v) {
  if (v.length === 0) return 1;
  let s = 0;
  for (const x of v) { if (x.riskLevel === "高") s += 3; else if (x.riskLevel === "中") s += 2; else s += 1; }
  return Math.min(10, Math.max(1, s));
}
function generateSummary(v, s) {
  if (v.length === 0) return `本合約未偵測到明顯違法條款，風險評分 ${s}/10。`;
  return `本合約共偵測到 ${v.length} 個疑似違法條款，風險評分 ${s}/10。建議簽署前諮詢專業人士。`;
}
